const categories = items[0].json.categories || [];
const alerts = [];
for (const cat of categories) {
  for (const t of (cat.tickers || [])) {
    const score = t.bull_score ?? 50;
    if (score >= 75) {
      alerts.push(`🟢 *${t.ticker}* — Bull Score ${score} (STARK BULLISH)`);
    } else if (score <= 25) {
      alerts.push(`🔴 *${t.ticker}* — Bull Score ${score} (STARK BEARISH)`);
    }
  }
}
if (alerts.length === 0) return [];
const msg = '📊 *Stock Alerts — ' + new Date().toLocaleDateString('de-DE') + '*\n\n' + alerts.join('\n');
return [{ json: { message: msg, count: alerts.length } }];
